package com.hospital.management.dao.impl;import com.hospital.management.dao.AdmissionDao;import com.hospital.management.model.*;import com.hospital.management.util.DatabaseConnectionManager;import java.sql.*;import java.time.*;import java.util.*;public class AdmissionDaoImpl implements AdmissionDao{private static final String S="SELECT a.*,p.PATIENT_NUMBER,p.FIRST_NAME||' '||p.LAST_NAME PATIENT_NAME,d.FIRST_NAME||' '||d.LAST_NAME DOCTOR_NAME,dep.DEPARTMENT_NAME,b.BED_NUMBER,r.ROOM_ID,r.ROOM_NUMBER,r.ROOM_TYPE,r.DAILY_RATE,u.USERNAME CREATED_BY_USERNAME,(SELECT MAX(bl.BILL_ID) FROM BILLS bl WHERE bl.PATIENT_ID=a.PATIENT_ID AND (bl.APPOINTMENT_ID=a.APPOINTMENT_ID OR a.APPOINTMENT_ID IS NULL)) BILL_ID FROM ADMISSIONS a JOIN PATIENTS p ON p.PATIENT_ID=a.PATIENT_ID JOIN DOCTORS d ON d.DOCTOR_ID=a.DOCTOR_ID JOIN DEPARTMENTS dep ON dep.DEPARTMENT_ID=a.DEPARTMENT_ID JOIN BEDS b ON b.BED_ID=a.BED_ID JOIN ROOMS r ON r.ROOM_ID=b.ROOM_ID JOIN USERS u ON u.USER_ID=a.CREATED_BY ";public Optional<Admission>findById(Long id)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection()){return one(c,"a.ADMISSION_ID",id,false);}}public Optional<Admission>findActiveByPatientId(Long id)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection()){return one(c,"a.PATIENT_ID",id,false," AND a.STATUS IN('ADMITTED','TRANSFERRED')");}}public Optional<Admission>lockById(Connection c,Long id)throws SQLException{return one(c,"a.ADMISSION_ID",id,true);}private Optional<Admission>one(Connection c,String f,Long id,boolean lock,String...extra)throws SQLException{try(PreparedStatement s=c.prepareStatement(S+"WHERE "+f+"=?"+(extra.length==0?"":extra[0])+(lock?" FOR UPDATE OF a.STATUS,a.BED_ID":""))){s.setLong(1,id);try(ResultSet r=s.executeQuery()){return r.next()?Optional.of(map(r)):Optional.empty();}}}public Page<Admission>findAll(PageRequest p,Long pi,Long di,Long dep,Long room,LocalDate from,LocalDate to,String st)throws SQLException{StringBuilder q=new StringBuilder(S+"WHERE 1=1 ");List<Object>x=new ArrayList<>();if(pi!=null){q.append("AND a.PATIENT_ID=? ");x.add(pi);}if(di!=null){q.append("AND a.DOCTOR_ID=? ");x.add(di);}if(dep!=null){q.append("AND a.DEPARTMENT_ID=? ");x.add(dep);}if(room!=null){q.append("AND r.ROOM_ID=? ");x.add(room);}if(st!=null&&!st.isBlank()){q.append("AND a.STATUS=? ");x.add(st.toUpperCase());}if(!p.getSearchTerm().isBlank()){q.append("AND UPPER(a.ADMISSION_NUMBER||' '||p.PATIENT_NUMBER||' '||p.FIRST_NAME||' '||p.LAST_NAME||' '||r.ROOM_NUMBER||' '||b.BED_NUMBER||' '||a.STATUS) LIKE ? ");x.add("%"+p.getSearchTerm().toUpperCase()+"%");}q.append("ORDER BY a.ADMISSION_DATE DESC,a.ADMISSION_ID DESC OFFSET ? ROWS FETCH NEXT ? ROWS ONLY");try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement(q.toString())){int i=1;for(Object v:x)s.setObject(i++,v);s.setInt(i++,p.getOffset());s.setInt(i,p.getPageSize());List<Admission>a=new ArrayList<>();try(ResultSet r=s.executeQuery()){while(r.next())a.add(map(r));}return new Page<>(a,p.getPageNumber(),p.getPageSize(),p.getOffset()+a.size());}}public long create(Connection c,Admission a)throws SQLException{try(PreparedStatement s=c.prepareStatement("INSERT INTO ADMISSIONS(ADMISSION_NUMBER,PATIENT_ID,DOCTOR_ID,DEPARTMENT_ID,APPOINTMENT_ID,BED_ID,ADMISSION_DATE,EXPECTED_DISCHARGE_DATE,ADMISSION_REASON,STATUS,CREATED_BY)VALUES(?,?,?,?,?,?,CURRENT_TIMESTAMP,?,?,?,?)",new String[]{"ADMISSION_ID"})){s.setString(1,a.getAdmissionNumber());s.setLong(2,a.getPatientId());s.setLong(3,a.getDoctorId());s.setLong(4,a.getDepartmentId());if(a.getAppointmentId()==null)s.setNull(5,Types.NUMERIC);else s.setLong(5,a.getAppointmentId());s.setLong(6,a.getBedId());if(a.getExpectedDischargeDate()==null)s.setNull(7,Types.DATE);else s.setDate(7,java.sql.Date.valueOf(a.getExpectedDischargeDate()));s.setString(8,a.getAdmissionReason());s.setString(9,a.getStatus());s.setLong(10,a.getCreatedBy());s.executeUpdate();try(ResultSet r=s.getGeneratedKeys()){return r.next()?r.getLong(1):0;}}}public boolean updateActiveAdmission(Connection c,Admission a)throws SQLException{try(PreparedStatement s=c.prepareStatement("UPDATE ADMISSIONS SET DOCTOR_ID=?,DEPARTMENT_ID=?,EXPECTED_DISCHARGE_DATE=?,ADMISSION_REASON=?,UPDATED_AT=CURRENT_TIMESTAMP WHERE ADMISSION_ID=? AND STATUS IN('ADMITTED','TRANSFERRED')")){s.setLong(1,a.getDoctorId());s.setLong(2,a.getDepartmentId());if(a.getExpectedDischargeDate()==null)s.setNull(3,Types.DATE);else s.setDate(3,java.sql.Date.valueOf(a.getExpectedDischargeDate()));s.setString(4,a.getAdmissionReason());s.setLong(5,a.getAdmissionId());return s.executeUpdate()==1;}}public boolean transferBed(Connection c,Long id,Long target,String st)throws SQLException{try(PreparedStatement s=c.prepareStatement("UPDATE ADMISSIONS SET BED_ID=?,STATUS=?,UPDATED_AT=CURRENT_TIMESTAMP WHERE ADMISSION_ID=? AND STATUS IN('ADMITTED','TRANSFERRED')")){s.setLong(1,target);s.setString(2,st);s.setLong(3,id);return s.executeUpdate()==1;}}public void recordTransfer(Connection c,Long id,Long from,Long to,String reason,Long user)throws SQLException{try(PreparedStatement s=c.prepareStatement("INSERT INTO ADMISSION_TRANSFERS(ADMISSION_ID,FROM_BED_ID,TO_BED_ID,TRANSFER_REASON,TRANSFERRED_BY)VALUES(?,?,?,?,?)")){s.setLong(1,id);s.setLong(2,from);s.setLong(3,to);s.setString(4,reason);s.setLong(5,user);s.executeUpdate();}}public boolean discharge(Connection c,Long id,LocalDateTime d,String summary,String st)throws SQLException{return finish(c,id,d,summary,st);}private boolean finish(Connection c,Long id,LocalDateTime d,String summary,String st)throws SQLException{try(PreparedStatement s=c.prepareStatement("UPDATE ADMISSIONS SET ACTUAL_DISCHARGE_DATE=?,DISCHARGE_SUMMARY=?,STATUS=?,UPDATED_AT=CURRENT_TIMESTAMP WHERE ADMISSION_ID=? AND STATUS IN('ADMITTED','TRANSFERRED')")){if(d==null)s.setNull(1,Types.TIMESTAMP);else s.setTimestamp(1,Timestamp.valueOf(d));s.setString(2,summary);s.setString(3,st);s.setLong(4,id);return s.executeUpdate()==1;}}public boolean cancel(Connection c,Long id,String st)throws SQLException{return finish(c,id,null,null,st);}public boolean existsActiveAdmissionForPatient(Long id)throws SQLException{return findActiveByPatientId(id).isPresent();}public boolean existsActiveAdmissionForBed(Long id)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement("SELECT 1 FROM ADMISSIONS WHERE BED_ID=? AND STATUS IN('ADMITTED','TRANSFERRED') FETCH FIRST 1 ROW ONLY")){s.setLong(1,id);try(ResultSet r=s.executeQuery()){return r.next();}}}private Admission map(ResultSet r)throws SQLException{Admission a=new Admission();a.setAdmissionId(r.getLong("ADMISSION_ID"));a.setAdmissionNumber(r.getString("ADMISSION_NUMBER"));a.setPatientId(r.getLong("PATIENT_ID"));a.setPatientNumber(r.getString("PATIENT_NUMBER"));a.setPatientName(r.getString("PATIENT_NAME"));a.setDoctorId(r.getLong("DOCTOR_ID"));a.setDoctorName(r.getString("DOCTOR_NAME"));a.setDepartmentId(r.getLong("DEPARTMENT_ID"));a.setDepartmentName(r.getString("DEPARTMENT_NAME"));long ap=r.getLong("APPOINTMENT_ID");a.setAppointmentId(r.wasNull()?null:ap);a.setBedId(r.getLong("BED_ID"));a.setBedNumber(r.getString("BED_NUMBER"));a.setRoomId(r.getLong("ROOM_ID"));a.setRoomNumber(r.getString("ROOM_NUMBER"));a.setRoomType(r.getString("ROOM_TYPE"));a.setDailyRate(r.getBigDecimal("DAILY_RATE"));a.setAdmissionReason(r.getString("ADMISSION_REASON"));a.setDischargeSummary(r.getString("DISCHARGE_SUMMARY"));a.setStatus(r.getString("STATUS"));a.setCreatedBy(r.getLong("CREATED_BY"));a.setCreatedByUsername(r.getString("CREATED_BY_USERNAME"));Timestamp ad=r.getTimestamp("ADMISSION_DATE"),dd=r.getTimestamp("ACTUAL_DISCHARGE_DATE");a.setAdmissionDate(ad==null?null:ad.toLocalDateTime());a.setActualDischargeDate(dd==null?null:dd.toLocalDateTime());java.sql.Date ed=r.getDate("EXPECTED_DISCHARGE_DATE");a.setExpectedDischargeDate(ed==null?null:ed.toLocalDate());long bill=r.getLong("BILL_ID");a.setBillId(r.wasNull()?null:bill);return a;}}
